<template>
  <view class="page">
    <view v-if="loading" class="empty-state">订单读取中</view>
    <block v-else-if="order">
      <view class="status-card"><text class="status-label">订单状态</text><text class="status-value">{{ order.status_text }}</text><text class="status-no">{{ order.order_no }}</text></view>
      <view v-if="order.order_notice" class="order-notice" :class="order.order_notice.type"><text class="order-notice-title">{{ order.order_notice.title }}</text><text class="order-notice-content">{{ order.order_notice.content }}</text></view>
      <view class="section"><text class="section-title">车辆信息</text><view class="info-row"><text>车辆</text><text>{{ order.car_name }}</text></view><view class="info-row"><text>车牌号</text><text>{{ order.plate_no || '待交车确认' }}</text></view><view class="info-row"><text>取车时间</text><text>{{ order.pickup_time }}</text></view><view class="info-row"><text>还车时间</text><text>{{ order.return_time }}</text></view><view class="info-row"><text>取车地点</text><text>{{ order.pickup_location || '市区门店' }}</text></view><view class="info-row"><text>还车地点</text><text>{{ order.return_location || '市区门店' }}</text></view><view v-if="order.actual_pickup_time" class="info-row"><text>实际交车</text><text>{{ order.actual_pickup_time }}</text></view><view v-if="order.actual_return_time" class="info-row"><text>实际还车</text><text>{{ order.actual_return_time }}</text></view></view>
      <view class="section"><text class="section-title">费用明细</text><view class="info-row"><text>基础租金</text><text>¥{{ order.base_amount }}</text></view><view class="info-row"><text>保险费用</text><text>¥{{ order.insurance_amount }}</text></view><view v-for="fee in bookingFees" :key="`booking-${fee.id}`" class="info-row fee-item"><view class="fee-item-main"><text>{{ fee.fee_name }}</text><text v-if="fee.category_path || fee.category_text" class="fee-category">{{ fee.category_path || fee.category_text }}</text></view><text>¥{{ fee.amount }}</text></view><view v-for="promotion in order.promotions || []" :key="promotion.rule_name" class="info-row discount"><text>{{ promotion.rule_name }}</text><text v-if="Number(promotion.discount_amount)>0">-¥{{ promotion.discount_amount }}</text><text v-else>完成后赠送积分</text></view><view class="info-row discount"><text>优惠金额</text><text>-¥{{ order.discount_amount }}</text></view><view class="info-row total"><text>应付租金</text><text>¥{{ order.total_amount }}</text></view><view class="info-row deposit"><text>另付押金</text><text>¥{{ order.deposit_amount }}</text></view></view>
      <view v-if="order.deposit" class="section"><text class="section-title">押金明细</text><view class="info-row"><text>已支付押金</text><text>¥{{ order.deposit.paid_amount }}</text></view><view class="info-row"><text>已扣押金</text><text>¥{{ order.deposit.deducted_amount }}</text></view><view class="info-row"><text>已退押金</text><text>¥{{ order.deposit.refunded_amount }}</text></view><view v-if="order.deposit.deduct_reason" class="section-note">扣款原因：{{ order.deposit.deduct_reason }}</view><view v-if="order.deposit.refunds?.length" class="section-note">退款将按原支付渠道退回</view></view>
      <view v-if="order.refunds?.length" class="section"><text class="section-title">退款进度</text><view v-for="refund in order.refunds" :key="refund.id" class="refund-card"><view class="info-row"><text>{{ refund.reason || '订单退款' }}</text><text>¥{{ refund.amount }}</text></view><text class="refund-status" :class="refund.status">{{ refund.status_text }}</text><text v-if="refund.refunded_at" class="section-note">到账时间：{{ refund.refunded_at }}</text><text v-else class="section-note">退款将原路退回，到账时间以支付渠道为准。</text></view></view>
      <view v-if="order.insurances?.length" class="section"><text class="section-title">已选保险</text><view v-for="insurance in order.insurances" :key="insurance.id" class="info-row"><text>{{ insurance.insurance_name }}</text><text>¥{{ insurance.amount }}</text></view></view>
      <view class="section"><text class="section-title">租赁合同</text><view class="info-row"><text>签署状态</text><text>{{ order.contract?.sign_status_text || (order.contract_status === 'signed' ? '已签署' : '待门店发起') }}</text></view><view v-if="order.contract?.contract_no" class="info-row"><text>合同编号</text><text>{{ order.contract.contract_no }}</text></view><text v-if="waitingForContract" class="section-note">正等待商家起草合同</text><block v-else-if="canSignContract"><text class="section-note contract-pending">待签署电子合同</text><button class="pay-button contract-sign-button" @click="signContract">去签合同</button></block><button v-if="order.contract?.contract_url" class="outline-button" @click="openContract">{{ canSignContract ? '查看合同内容' : '查看合同凭证' }}</button><text class="section-note">合同由门店发起并在签署完成后留存。</text></view>
      <view v-if="order.inspections?.length" class="section">
        <text class="section-title">交还车确认单</text>
        <view v-for="inspection in order.inspections" :key="inspection.id" class="inspection-card">
          <view class="inspection-head"><text>{{ inspection.inspection_type_text }}</text><text>{{ inspection.created_at }}</text></view>
          <view class="inspection-meta"><text>里程 {{ inspection.mileage }} km</text><text v-if="inspection.energy_level !== null">油电量 {{ inspection.energy_level }}%</text></view>
          <text v-if="inspection.exterior_status" class="inspection-note">外观：{{ inspection.exterior_status }}</text>
          <text v-if="inspection.interior_status" class="inspection-note">内饰：{{ inspection.interior_status }}</text>
          <text v-if="inspection.tire_status" class="inspection-note">轮胎：{{ inspection.tire_status }}</text>
          <text v-if="inspection.glass_status" class="inspection-note">玻璃：{{ inspection.glass_status }}</text>
          <text v-if="inspection.remark" class="inspection-note">备注：{{ inspection.remark }}</text>
          <view v-if="inspection.proposed_fees?.length || inspection.proposed_fee" class="fee-box"><text>本次拟收费用</text><view v-for="(fee, feeIndex) in (inspection.proposed_fees?.length ? inspection.proposed_fees : [inspection.proposed_fee])" :key="`${fee.category_id || feeIndex}-${feeIndex}`" class="proposed-fee"><text class="fee-category">{{ fee.category_path || fee.category_text }}</text><text>{{ fee.name }} ¥{{ fee.amount }}</text><text v-if="fee.remark">{{ fee.remark }}</text></view></view>
          <view v-if="inspection.media?.length" class="media-grid"><view v-for="media in inspection.media" :key="media.url" class="inspection-media"><text class="media-scene">{{ media.scene_text || '其他补充' }}</text><image v-if="media.media_type === 'image'" class="media-image" :src="media.url" mode="aspectFill" @click="preview([media.url])"/><view v-else class="video-note">现场视频已留存</view></view></view>
          <template v-if="inspection.customer_confirm_status === 'pending'"><text class="section-note">请核对以上车况、随车物品和现场证据后确认。</text><view class="inline-actions"><button class="pay-button" @click="signInspection(inspection)">签名确认</button><button class="cancel-button" @click="disputeInspection(inspection)">提出异议</button></view></template>
          <template v-else-if="inspection.customer_confirm_status === 'confirmed'"><text class="confirmed">已完成用户签名确认</text><text v-if="inspection.customer_confirmed_at" class="section-note">确认时间：{{ inspection.customer_confirmed_at }}</text></template>
          <template v-else><text class="warn">已提交验车异议：{{ inspection.customer_dispute_reason || '等待门店处理' }}</text><view v-if="inspection.customer_dispute_evidence?.length" class="media-grid"><image v-for="url in inspection.customer_dispute_evidence" :key="url" class="media-image" :src="url" mode="aspectFill" @click="preview(inspection.customer_dispute_evidence)"/></view></template>
        </view>
      </view>
      <view v-if="order.damage_claims?.length || order.violations?.length" class="section"><text class="section-title">费用认定凭证</text><view v-for="claim in order.damage_claims" :key="`damage-${claim.id}`" class="evidence-card"><text class="evidence-title">车损：{{ claim.damage_part }} · {{ claim.damage_type || '其他' }}</text><text class="evidence-note">{{ claim.description || '门店已上传车损认定说明' }}</text><view class="info-row"><text>责任认定</text><text>{{ claim.liable_party }}</text></view><view class="info-row"><text>认定金额</text><text>¥{{ claim.approved_amount }}</text></view><view v-if="claim.evidence?.length" class="media-grid"><image v-for="url in claim.evidence" :key="url" class="media-image" :src="url" mode="aspectFill" @click="preview([url])"/></view></view><view v-for="item in order.violations" :key="`violation-${item.id}`" class="evidence-card"><text class="evidence-title">违章记录</text><text class="evidence-note">{{ item.description || item.location || '违章待处理' }}</text><view class="info-row"><text>罚款金额</text><text>¥{{ item.fine_amount }}</text></view><view class="info-row"><text>扣分</text><text>{{ item.points_deducted }} 分</text></view><view v-if="item.evidence_images?.length" class="media-grid"><image v-for="url in item.evidence_images" :key="url" class="media-image" :src="url" mode="aspectFill" @click="preview([url])"/></view></view></view>
      <view v-if="order.settlements?.length" class="section"><text class="section-title">还车结算单</text><view v-for="settlement in order.settlements" :key="settlement.id" class="settlement-card"><view class="inspection-head"><text>{{ settlement.settlement_no }}</text><text>{{ settlement.status }}</text></view><view v-for="item in settlement.items" :key="`${item.source_type}-${item.source_id}`" class="info-row fee-item"><view class="fee-item-main"><text>{{ item.name }}</text><text v-if="item.category_path || item.category_text" class="fee-category">{{ item.category_path || item.category_text }}</text></view><text>¥{{ item.amount }}</text></view><view class="info-row total"><text>附加费用</text><text>¥{{ settlement.additional_fee_amount }}</text></view><view class="info-row"><text>押金抵扣</text><text>-¥{{ settlement.deposit_deduct_amount }}</text></view><view class="info-row"><text>应退押金</text><text>¥{{ settlement.refundable_deposit_amount }}</text></view><view v-if="Number(settlement.extra_payable_amount)>0" class="info-row total"><text>需补缴</text><text>¥{{ settlement.extra_payable_amount }}</text></view><text v-if="settlement.dispute_reason" class="warn">争议原因：{{ settlement.dispute_reason }}</text><text v-if="settlement.dispute_resolution" class="resolution">门店处理：{{ settlement.dispute_resolution }}</text><view v-if="settlement.evidence?.user_dispute_evidence?.length" class="media-grid"><image v-for="url in settlement.evidence.user_dispute_evidence" :key="url" class="media-image" :src="url" mode="aspectFill" @click="preview(settlement.evidence.user_dispute_evidence)"/></view><view v-if="settlement.status === 'pending_confirmation'" class="inline-actions"><button class="pay-button" @click="signSettlement(settlement)">签名确认</button><button class="cancel-button" @click="disputeSettlement(settlement)">提出争议</button></view><button v-if="settlement.status === 'pending_payment'" class="pay-button" @click="paySettlement(settlement)">补缴费用 ¥{{ settlement.extra_payable_amount }}</button><text v-if="settlement.status === 'settled'" class="confirmed">结算完成</text></view></view>
      <view v-if="order.status === 'completed'" class="section"><text class="section-title">订单评价</text><template v-if="order.review"><text v-if="order.review.is_auto" class="section-note">订单已由系统自动确认，未产生用户评分。</text><template v-else><view class="info-row"><text>整体评分</text><text class="review-score">{{ order.review.overall_rating }} / 5</text></view><view class="info-row"><text>车辆状况</text><text>{{ order.review.vehicle_rating }} / 5</text></view><view class="info-row"><text>交接服务</text><text>{{ order.review.handover_rating }} / 5</text></view><view class="info-row"><text>价格透明</text><text>{{ order.review.price_rating || '-' }} / 5</text></view><view class="info-row"><text>服务效率</text><text>{{ order.review.efficiency_rating || '-' }} / 5</text></view><view v-if="order.review.tags?.length" class="review-tags"><text v-for="tag in order.review.tags" :key="tag">{{ tag }}</text></view><text v-if="order.review.content" class="review-content">{{ order.review.content }}</text><view v-if="order.review.images?.length" class="media-grid"><image v-for="url in order.review.images" :key="url" class="media-image" :src="url" mode="aspectFill" @click="preview(order.review.images)"/></view><view v-if="order.review.reply_content" class="merchant-reply"><text>商家回复</text><text>{{ order.review.reply_content }}</text></view><view v-if="order.review.followup_content" class="merchant-reply"><text>我的补充</text><text>{{ order.review.followup_content }}</text><view v-if="order.review.followup_images?.length" class="media-grid"><image v-for="url in order.review.followup_images" :key="url" class="media-image" :src="url" mode="aspectFill" @click="preview(order.review.followup_images)"/></view></view><view v-if="order.review.status === 'approved'" class="review-actions"><button v-if="order.review.can_followup" class="outline-button" @click="followUpReview">补充评价</button><button class="outline-button" @click="appealReview">评价申诉</button><button class="outline-button danger" @click="hideReview">隐藏评价</button></view><text v-else class="section-note">该评价已隐藏，不再公开展示。</text></template></template><template v-else><text class="section-note">分享本次用车体验，帮助我们持续改进。</text><button class="pay-button review-button" @click="writeReview">去评价</button></template></view>
      <view v-if="order.timeline?.length" class="section"><text class="section-title">订单时间线</text><view v-for="(item,index) in order.timeline" :key="`${item.time}-${index}`" class="timeline"><view class="dot"></view><view><text class="timeline-title">{{ item.title }}</text><text class="timeline-time">{{ item.time }}</text></view></view></view>
      <view v-if="canPay || canPayDeposit || canCancel" class="action-section"><button v-if="canPay" class="pay-button" @click="payOrder">支付租金</button><button v-if="canPayDeposit" class="pay-button" @click="payDeposit">支付押金</button><button v-if="canPayDeposit && creditDepositAvailable" class="credit-button" @click="chooseCreditDeposit">信用免押</button><button v-else-if="canCancel" class="cancel-button" @click="cancelOrder">取消订单</button><text v-if="canPayDeposit && !creditDepositAvailable" class="credit-notice">{{ order.rental_access?.notice || '当前订单暂不支持信用免押，请支付普通押金。' }}</text></view>
      <CreditDepositQrModal v-model="alipayQrVisible" :order-no="order.order_no" :amount="order.deposit_amount" />
    </block><view v-else class="empty-state">订单不存在或已失效</view>
  </view>
</template>
<script setup>
import { computed, ref } from 'vue'
import { onLoad, onShow } from '@dcloudio/uni-app'
import CreditDepositQrModal from '../../components/CreditDepositQrModal.vue'
import { cancelRentalOrder, confirmRentalMockPayment, getRentalOrder, payRentalSettlement, prepareRentalCreditDeposit } from '../../api/rental'
import { appealOrderReview, hideOrderReview } from '../../api/review'
const order = ref(null); const loading = ref(true); const orderId = ref(0); const alipayQrVisible = ref(false)
const canPay = computed(() => order.value?.status === 'pending_payment' && order.value?.payment_status !== 'paid')
const bookingFees = computed(() => (order.value?.fees || []).filter((fee) => fee.settlement_stage === 'booking'))
const canPayDeposit = computed(() => order.value?.status === 'pending_deposit' && order.value?.deposit_status !== 'paid' && Number(order.value?.deposit_amount) > 0)
const creditDepositAvailable = computed(() => order.value?.rental_access?.credit_deposit_available !== false)
const canCancel = computed(() => order.value && ['pending_payment','pending_deposit','pending_review','reserved','pending_pickup'].includes(order.value.status))
const contractStageReady = computed(() => ['paid', 'not_required'].includes(order.value?.deposit_status) && ['reserved', 'pending_pickup'].includes(order.value?.status))
const waitingForContract = computed(() => contractStageReady.value && !order.value?.contract)
const canSignContract = computed(() => contractStageReady.value && !!order.value?.contract?.id && !!order.value?.contract?.contract_url && ['unsigned', 'pending_user_sign', 'signing'].includes(order.value.contract.sign_status))
const loadOrder = async (id = orderId.value) => { if (!id) return; try { const result = await getRentalOrder(id); order.value = result.data?.order || null } catch (error) { uni.showToast({ title:error.msg || '订单读取失败',icon:'none' }) } finally { loading.value=false } }
const completePayment = async (requestPayment, label) => { try { uni.showLoading({title:'正在发起支付',mask:true}); const result=await requestPayment(); const p=result.data||{}; if(p.mock_callback_enabled){await confirmRentalMockPayment(p.payment_id,p.platform);uni.hideLoading();uni.showToast({title:`${label}成功`,icon:'success'});return loadOrder()} uni.hideLoading();uni.showModal({title:'支付前校验通过',content:'支付通道参数尚未配置，当前订单已完成支付前校验。',showCancel:false}) } catch(e){uni.hideLoading();uni.showToast({title:e.msg||`${label}失败`,icon:'none'});loadOrder()} }
const payOrder = () => uni.navigateTo({ url: `/pages/order/payment?id=${order.value.id}` })
const payDeposit = () => uni.navigateTo({ url: `/pages/order/payment?id=${order.value.id}&type=deposit` })
const paySettlement = (s) => completePayment(() => payRentalSettlement(s.id),'补缴')
const chooseCreditDeposit = () => uni.showActionSheet({ itemList: ['微信信用免押', '支付宝信用免押'], success: async ({ tapIndex }) => { const provider = tapIndex === 0 ? 'wechat' : 'alipay'; try { uni.showLoading({ title: '正在发起授权', mask: true }); const result = await prepareRentalCreditDeposit(order.value.id, provider); uni.hideLoading(); if (provider === 'alipay') { alipayQrVisible.value = true; return } const data = result.data || {}; if (!data.gateway_configured) { uni.showModal({ title: '微信信用免押', content: result.msg || '微信信用免押接口待配置', showCancel: false }); return } uni.showModal({ title: '微信信用免押', content: '微信信用授权参数已准备，接入正式凭证后将在此唤起授权。', showCancel: false }); } catch (error) { uni.hideLoading(); uni.showToast({ title: error.msg || '信用免押发起失败', icon: 'none' }); } } })
const signInspection = (i) => uni.navigateTo({url:`/pages/order/signature?mode=inspection&id=${i.id}&order_id=${orderId.value}&inspection_type=${i.inspection_type}&hash=${encodeURIComponent(i.content_hash || '')}`})
const disputeInspection = (i) => uni.navigateTo({ url: `/pages/order/inspection-dispute?id=${i.id}&hash=${encodeURIComponent(i.content_hash || '')}` })
const signSettlement = (s) => uni.navigateTo({url:`/pages/order/signature?mode=settlement&id=${s.id}&order_id=${orderId.value}`})
const disputeSettlement = (s) => uni.navigateTo({ url: `/pages/order/dispute?id=${s.id}` })
const preview = (urls) => uni.previewImage({ urls, current: urls[0] })
const openContract = () => uni.downloadFile({ url: order.value.contract.contract_url, success: r => uni.openDocument({ filePath:r.tempFilePath, showMenu:true }), fail:()=>uni.showToast({title:'合同下载失败',icon:'none'}) })
const signContract = () => uni.navigateTo({ url: `/pages/order/signature?mode=contract&id=${order.value.contract.id}&order_id=${order.value.id}&contract_url=${encodeURIComponent(order.value.contract.contract_url)}` })
const writeReview = () => uni.navigateTo({ url: `/pages/order/review?type=rental&id=${order.value.id}` })
const followUpReview = () => uni.navigateTo({ url: `/pages/order/review-followup?id=${order.value.review.id}` })
const hideReview = () => uni.showModal({title:'隐藏评价',content:'隐藏后评价不再公开展示，是否继续？',success:async({confirm})=>{if(!confirm)return;try{await hideOrderReview(order.value.review.id);uni.showToast({title:'评价已隐藏',icon:'success'});loadOrder()}catch(error){uni.showToast({title:error.msg||'操作失败',icon:'none'})}}})
const appealReview = () => uni.showModal({title:'评价申诉',editable:true,placeholderText:'请填写申诉说明',content:'提交后将由门店处理。',success:async({confirm,content})=>{if(!confirm)return;try{await appealOrderReview(order.value.review.id,{reason:content||''});uni.showToast({title:'申诉已提交',icon:'success'})}catch(error){uni.showToast({title:error.msg||'提交失败',icon:'none'})}}})
const cancelOrder = () => uni.showModal({title:'取消订单',content:'确认取消这笔租车订单吗？',success:async r=>{if(!r.confirm)return;try{const x=await cancelRentalOrder(order.value.id);uni.showToast({title:x.data?.message||'订单已取消',icon:'none'});loadOrder()}catch(e){uni.showToast({title:e.msg||'取消失败',icon:'none'})}}})
onLoad(({id})=>{orderId.value=Number(id);loadOrder(orderId.value)});onShow(()=>{if(orderId.value&&!loading.value)loadOrder()})
